import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.Request
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET
import java.util.concurrent.TimeUnit

const val API_BASE_URL_DEV = "https://api-dev.example.com/"
const val API_BASE_URL_STAGING = "https://api-staging.example.com/"
const val API_BASE_URL_PROD = "https://api.example.com/"

private const val TAG = "NetworkModule"

interface ApiService {
    @GET("/users")
    suspend fun getUsers(): List<User>
}

class NetworkModule(private val token: String, private val baseUrl: String) {

    private val client = OkHttpClient.Builder()
        .connectTimeout(10, TimeUnit.SECONDS)
        .writeTimeout(10, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()

    fun provideApiService(): ApiService {
        return Retrofit.Builder()
            .baseUrl(baseUrl)
            .client(client)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(ApiService::class.java)
    }
}

class AuthInterceptor(private val token: String) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        var request = chain.request()

        request = request.newBuilder()
            .header("Authorization", "Bearer $token")
            .build()

        return chain.proceed(request)
    }
}

class NetworkModuleProvider(
    private val token: String,
    private val isDevBuild: Boolean
) {

    fun provideNetworkModule(): NetworkModule {
        val baseUrl = if (isDevBuild) API_BASE_URL_DEV else if (isStagingBuild) API_BASE_URL_STAGING else API_BASE_URL_PROD

        val interceptor = AuthInterceptor(token)
        val client = OkHttpClient.Builder()
            .addInterceptor(interceptor)
            .build()

        return NetworkModule(token, baseUrl)
    }
}

